from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

# Mock secret key for JWT decoding (use a real secret in production)
JWT_SECRET_KEY = 'your_jwt_secret_key'

@app.route('/api', methods=['GET'])
def api():
    # Extract token from Authorization header
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Missing authorization header'}), 401

    try:
        # Decode JWT token (do not verify signature for development)
        token = auth_header.split()[1]
        decoded_token = jwt.decode(token, JWT_SECRET_KEY, algorithms=['HS256'], verify=False)

        # Extract user claims
        user_claims = decoded_token.get('user', {})

        # Forward user claims to backend services (mocked here)
        return jsonify({'message': 'Success', 'user_claims': user_claims}), 200

    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)